  "SAPPHIRE": {
   "name": "SAPPHIRE",
   "file": "oracle.zil",
   "line": 450,
   "endLine": 477,
   "desc": "sapphire",
   "ldesc": null,
   "fdesc": "In the bony hand of one of the skeletons, locked in its death grip, is\na stunningly beautiful sapphire.",
   "loc": "IRON-MINE",
   "flags": [
    "TAKEBIT",
    "TRYTAKEBIT"
   ],
   "synonyms": [
    "SAPPHIRE",
    "JEWEL",
    "JERRIMORE"
   ],
   "adjectives": [
    "STUNNING",
    "STUNNINGLY",
    "BEAUTIFUL",
    "CURSED",
    "ACCURSED"
   ],
   "action": "SAPPHIRE-F",
   "descfcn": null,
   "contfcn": null,
   "globals": [],
   "pseudo": [],
   "otherProps": {
    "SIZE": [
     "3"
    ],
    "OWNER": [
     "SAPPHIRE"
    ],
    "RESEARCH": [
     "\"The legend of the accursed Jewel of Jerrimore can trace its origins to\nthe third century B.E. in the northlands of Frobozz. This jewel, which in\nmost versions of the legend is a star sapphire, is said to have been cursed\nby the Mage of Jerrimore as he lay upon his deathbed.|\n   As he sickened, this powerful but twisted wizard became convinced that\nhis enemies had poisoned him to gain possession of his greatest treasure,\nthe Jewel of Jerrimore. With his dying breath, he loosed a great and evil\ncurse upon the Jewel and all who would possess it.|\n   After the Mage's death, each of his heirs took possession of the jewel;\neach held it jealously, mistrusting any who might look upon it; each became\nobsessed with the greed and treachery they perceived around them; and each\ncame to early and horrible deaths. Thus grew the legend of the cursed Jewel.|\n   Although the legends vary, all versions say that the Jewel travelled\nthrough many lands, always leaving a wake of misery and death, and finally\nbecame lost in a forgotten iron mine.\""
    ]
   },
   "contents": [],
   "source": "<OBJECT SAPPHIRE\n\t(LOC IRON-MINE)\n\t(DESC \"sapphire\")\n\t(FDESC\n\"In the bony hand of one of the skeletons, locked in its death grip, is\na stunningly beautiful sapphire.\")\n\t(SYNONYM SAPPHIRE JEWEL JERRIMORE)\n\t(ADJECTIVE STUNNING STUNNINGLY BEAUTIFUL CURSED ACCURSED)\n\t(FLAGS TAKEBIT TRYTAKEBIT)\n\t(SIZE 3)\n\t(OWNER SAPPHIRE)\n\t(RESEARCH\n\"\\\"The legend of the accursed Jewel of Jerrimore can trace its origins to\nthe third century B.E. in the northlands of Frobozz. This jewel, which in\nmost versions of the legend is a star sapphire, is said to have been cursed\nby the Mage of Jerrimore as he lay upon his deathbed.|\n   As he sickened, this powerful but twisted wizard became convinced that\nhis enemies had poisoned him to gain possession of his greatest treasure,\nthe Jewel of Jerrimore. With his dying breath, he loosed a great and evil\ncurse upon the Jewel and all who would possess it.|\n   After the Mage's death, each of his heirs took possession of the jewel;\neach held it jealously, mistrusting any who might look upon it; each became\nobsessed with the greed and treachery they perceived around them; and each\ncame to early and horrible deaths. Thus grew the legend of the cursed Jewel.|\n   Although the legends vary, all versions say that the Jewel travelled\nthrough many lands, always leaving a wake of misery and death, and finally\nbecame lost in a forgotten iron mine.\\\"\")\n\t(ACTION SAPPHIRE-F)>",
   "referencedBy": [
    "BOWL-F",
    "DEPRESSION-F",
    "SAPPHIRE-F",
    "MIRROR-F",
    "QUARRY-F"
   ]
  },
