  "MEGABOZ-HUT-F": {
   "name": "MEGABOZ-HUT-F",
   "file": "oracle.zil",
   "line": 1771,
   "endLine": 1777,
   "source": "<ROUTINE MEGABOZ-HUT-F (\"OPT\" (RARG <>))\n\t <COND (<EQUAL? .RARG ,M-LOOK>\n\t\t<TELL\n\"You are in the unassuming shack where the legendary magician Megaboz once\nlived. Embroidered wall hangings adorn one side of the hut, and a poem has\nbeen scrawled on the opposite wall; oddly, some of the words are missing.\nThe only exit is east. \" ,MEGABOZ-CEILING-DESC>)>>"
  },
