   "kind": "constant",
   "file": "prologue.zil",
   "line": 556,
   "value": "<PTABLE ;0 \"wait\" ;\"should be impossible to get this one\" ;1 \"go northeast\" ;2 \"walk south\" ;3 \"go west\" ;4 \"walk east\" ;5 \"enter the banquet hall\" ;\"west\" ;6 \"examine the gaunt man\" ;7 \"dive under the table\" ;8 \"get out from under the table\" ;9 \"pick up the scrap of parchment\" ;10 \"north\" ;\"only happens if you already went in the wrong direction\" ;11 \"southeast\" ;\"ditto\">"
