  "CAULDRON-DESCS": {
   "name": "CAULDRON-DESCS",
   "kind": "constant",
   "file": "prologue.zil",
   "line": 1144,
   "value": "<PTABLE ;0 \"barely bubbling\" ;1 \"bubbling quietly\" ;2 \"bubbling actively\" ;3 \"bubbling very actively\" ;4 \"bubbling and churning\" ;5 \"bubbling, churning, and smoking heavily\" ;6 \"churning actively and emitting large puffs of smoke\" ;7 \"violently churning and emitting huge puffs of dark smoke\" ;8 \"churning very violently and giving off clouds of black smoke\" ;9 \"churning and roiling beneath a whirlpool of thick black smoke\" ;10 \"boiling violently beneath a gathering storm of noisome smoke\" ;11 \"boiling with amazing energy, sending steaming geysers shooting\nup into the roiling black clouds which swirl around it\" ;12 \"almost lost amongst the clouds of dark power and energy which\nsurround the kettle, glowing and expanding from explosions deep within\">"
  },
  "MEGABOZ-TEXT": {
   "name": "MEGABOZ-TEXT",
   "kind": "constant",
   "file": "prologue.zil",
   "line": 1239,
   "value": "\"Megaboz was a mysterious wizard who lived a hermit's life in the Fublio\nValley. Some say he cast a Curse which will someday destroy the Empire, but\nroyal spokesmen have denied all such rumors. Megaboz vanished in 789 GUE;\nit is said that the effort of casting the Curse destroyed him.\""
  },
